frappe.ui.form.on("Salary Structure Assignment", {
    negotiated_net: function(frm) {
        if (!frm.doc.negotiated_net) return;

        // Simplified URA PAYE: all employees fall between 410,001 and 10,000,000
        function compute_paye(basic) {
            return 25000 + 0.30 * (gross - 410000);
        }

        let net_target = frm.doc.negotiated_net;
        let gross = net_target / 0.75;   // initial guess

        // Iterate until Net ≈ Negotiated Net
        for (let i = 0; i < 50; i++) {
            let transport = 0.15 * gross;
            let accommodation = 0.15 * gross;
            let lunch = 0.10 * gross;
            let basic = gross - (transport + accommodation + lunch);

            let nssf_employee = 0.05 * gross;
            let paye = compute_paye(gross);

            let net = gross - nssf_employee - paye;

            if (Math.abs(net - net_target) < 0.1) {
                break;
            }
            gross = gross + (net_target - net); // refine gross iteratively
        }

        // Final values
        let transport = 0.15 * gross;
        let accommodation = 0.15 * gross;
        let lunch = 0.10 * gross;
        let basic = gross - (transport + accommodation + lunch);
        let nssf_employee = 0.05 * gross;
        let paye = compute_paye(gross);
        let nssf_employer = 0.10 * gross;
        let net = gross - nssf_employee - paye;
        let ctc = gross + nssf_employer;

        // Set Base field (Gross Pay)
        frm.set_value("base", Math.round(gross));

        // 🔹 Update or insert PAYE (From Taxable)
        let paye_row = (frm.doc.deductions || []).find(d => d.salary_component === "PAYE (From Taxable)");
        if (paye_row) {
            paye_row.amount = Math.round(paye);
        } else {
            frm.add_child("deductions", {
                salary_component: "PAYE (From Taxable)",
                amount: Math.round(paye)
            });
        }
        frm.refresh_field("deductions");

        // 🔹 Always show popup breakdown
        frappe.msgprint({
            title: __("Salary Breakdown"),
            indicator: "blue",
            message: `
                <b>Negotiated Net:</b> ${net_target.toLocaleString()} UGX<br><br>
                <b>Gross Pay (Base):</b> ${gross.toFixed(0)} UGX<br>
                ├── Basic Salary (Taxable): ${basic.toFixed(0)} UGX<br>
                ├── Transport Allowance: ${transport.toFixed(0)} UGX<br>
                ├── Accommodation Allowance: ${accommodation.toFixed(0)} UGX<br>
                ├── Lunch Allowance: ${lunch.toFixed(0)} UGX<br><br>
                <b>Deductions:</b><br>
                ├── NSSF Employee (5%): ${nssf_employee.toFixed(0)} UGX<br>
                ├── PAYE (From Taxable): ${paye.toFixed(0)} UGX<br><br>
                <b>Net Pay:</b> ${net.toFixed(0)} UGX<br>
                <b>Employer NSSF (10%):</b> ${nssf_employer.toFixed(0)} UGX<br>
                <b>Cost to Company (CTC):</b> ${ctc.toFixed(0)} UGX
            `
        });
    }
});

frappe.ui.form.on('Leave Application', {
	refresh(frm) {
		add_reject_with_reason_button(frm);
	}
});

function add_reject_with_reason_button(frm) {
	// Adjust these to match your actual workflow states
	const rejectable_states = ['Open', 'Pending'];

	// Show only on saved docs and only in allowed states
	if (frm.is_new() || !rejectable_states.includes(frm.doc.workflow_state)) {
		return;
	}

	// Avoid duplicate button on refresh
	if (frm.custom_reject_with_reason_added) {
		return;
	}
	frm.custom_reject_with_reason_added = true;

	frm.add_custom_button(__('Reject with Reason'), () => {
		const dialog = new frappe.ui.Dialog({
			title: __('Reject Leave Application'),
			size: 'small',
			fields: [
				{
					label: __('Rejection Reason'),
					fieldname: 'custom_rejection_reason',
					fieldtype: 'Small Text',
					reqd: 1,
					description: __('Provide a clear and professional reason for rejecting this leave request.')
				}
			],
			primary_action_label: __('Save Reason'),
			primary_action: async (values) => {
				const reason = (values.custom_rejection_reason || '').trim();

				if (!reason) {
					frappe.msgprint({
						title: __('Reason Required'),
						message: __('Please enter the rejection reason before continuing.'),
						indicator: 'red'
					});
					return;
				}

				try {
					await frm.set_value('custom_rejection_reason', reason);

					if (frm.is_dirty()) {
						await frm.save();
					}

					dialog.hide();

					frappe.msgprint({
						title: __('Reason Saved'),
						message: __(
							'The rejection reason has been saved. You can now click the standard <b>Reject</b> workflow action.'
						),
						indicator: 'orange'
					});
				} catch (e) {
					frappe.msgprint({
						title: __('Save Failed'),
						message: __('Could not save the rejection reason. Please try again.'),
						indicator: 'red'
					});
				}
			}
		});

		dialog.show();

		setTimeout(() => {
			dialog.get_input('custom_rejection_reason')?.focus();
		}, 200);
	});
}
